class Solution:
    def getKth(self, lo, hi, k):
        def power(x):
            steps = 0
            while x != 1:
                x = x // 2 if x % 2 == 0 else 3 * x + 1
                steps += 1
            return steps
        nums = sorted(range(lo, hi + 1), key=lambda x: (power(x), x))
        return nums[k - 1]

