class Solution:
    def getKth(self, lo, hi, k):
        memo = {1: 0}
        def power(x):
            if x in memo:
                return memo[x]
            nxt = x // 2 if x % 2 == 0 else 3 * x + 1
            memo[x] = 1 + power(nxt)
            return memo[x]
        import sys
        sys.setrecursionlimit(10000)
        nums = sorted(range(lo, hi + 1), key=lambda x: (power(x), x))
        return nums[k - 1]

